// 部署 + キーワードからtaskModeを判定
const rd = $('Execute Workflow Trigger').item.json.runData;
const input = (rd.input ?? '').toLowerCase();
const dept = rd.department ?? 'GENERAL';
const hint = (rd.taskType ?? '').toLowerCase();

// キーワードマッチ
const kw = (words) => words.some(w => input.includes(w.toLowerCase()) || hint.includes(w.toLowerCase()));

let taskMode = 'general';

if (kw(['メール','email','mail','送信','送って'])) taskMode = 'email';
else if (kw(['議事録','商談メモ','ミーティング','会議メモ'])) taskMode = 'meeting_notes';
else if (kw(['提案書','企画書','ドキュメント','資料','報告書','レポート'])) taskMode = 'proposal';
else if (kw(['スケジュール','空き','日程','カレンダー','予定'])) taskMode = 'schedule';
else if (kw(['SNS','投稿','ツイート','twitter','instagram','linkedin','ポスト'])) taskMode = 'sns';
else if (kw(['コンテンツカレンダー','投稿計画','投稿スケジュール'])) taskMode = 'content_calendar';
else if (kw(['領収書','レシート','経費'])) taskMode = 'receipt_summary';
else if (kw(['経費レポート','月次','予算'])) taskMode = 'expense_report';
else if (kw(['請求書','インボイス'])) taskMode = 'invoice_check';
else if (kw(['市場分析','競合分析','マーケット','市場調査','SWOT'])) taskMode = 'market_analysis';
else if (kw(['グラフ','チャート','可視化','KPI','統計','トレンド'])) taskMode = 'data_visualization';
// 部署ベースのフォールバック
else if (dept === 'SALES') taskMode = 'proposal';
else if (dept === 'MARKETING') taskMode = 'sns';
else if (dept === 'ACCOUNTING') taskMode = 'expense_report';
else if (dept === 'ANALYTICS') taskMode = 'market_analysis';

return [{ json: { taskMode, department: dept, input: rd.input } }];
